@app.before_request
def before_request():
    request._start_time = time.perf_counter()
    endpoint = request.url_rule.rule if request.url_rule else request.path
    request._metrics_endpoint = endpoint
    inprogress_requests.labels(method=request.method, endpoint=endpoint).inc()


@app.after_request
def after_request(response):
    start_time = getattr(request, "_start_time", None)
    endpoint = getattr(request, "_metrics_endpoint", request.path)
    if start_time is not None:
        latency = time.perf_counter() - start_time
        http_request_latency_seconds.labels(
            method=request.method, endpoint=endpoint
        ).observe(latency)
    http_requests_total.labels(
        method=request.method, endpoint=endpoint, status=str(response.status_code)
    ).inc()
    inprogress_requests.labels(method=request.method, endpoint=endpoint).dec()
    return response


@app.errorhandler(Exception)
def handle_exception(error):
    endpoint = getattr(request, "_metrics_endpoint", request.path)
    http_requests_total.labels(
        method=request.method, endpoint=endpoint, status="500"
    ).inc()
    try:
        inprogress_requests.labels(method=request.method, endpoint=endpoint).dec()
    except Exception:
        pass
    return jsonify({"error": "internal server error"}), 500


@app.route("/")
def index():
    return jsonify({"service": "flask-prometheus-app", "status": "ok"})


@app.route("/health")
def health():
    return jsonify({"status": "healthy"})


@app.route("/orders", methods=["POST"])
def create_order():
    payload = request.get_json(silent=True) or {}
    amount = float(payload.get("amount", random.uniform(20, 500)))
    success = payload.get("success", True)

    order_value_amount.observe(amount)

    if success:
        orders_created_total.labels(status="success").inc()
        active_users.inc()
        inventory_level.labels(item="widget").dec()
        return jsonify({"message": "order created", "amount": amount}), 201

    orders_created_total.labels(status="failed").inc()
    return jsonify({"message": "order failed", "amount": amount}), 400


@app.route("/users/active", methods=["GET", "POST"])
def users_active():
    if request.method == "POST":
        payload = request.get_json(silent=True) or {}
        value = int(payload.get("value", 0))
        active_users.set(value)
        return jsonify({"active_users": value})
    return jsonify({"active_users": active_users._value.get()})


@app.route("/jobs/process", methods=["POST"])
def process_job():
    payload = request.get_json(silent=True) or {}
    job_type = payload.get("job_type", "default")
    result = payload.get("result", "success")
    queue_name = payload.get("queue", "default")

    jobs_processed_total.labels(job_type=job_type, result=result).inc()
    current_depth = queue_depth.labels(queue=queue_name)._value.get()
    queue_depth.labels(queue=queue_name).set(max(0, current_depth - 1))

    return jsonify({"job_type": job_type, "result": result, "queue": queue_name})


@app.route("/inventory/<item>", methods=["GET", "POST"])
def inventory(item):
    if request.method == "POST":
        payload = request.get_json(silent=True) or {}
        value = int(payload.get("value", 0))
        inventory_level.labels(item=item).set(value)
        return jsonify({"item": item, "inventory": value})
    return jsonify({"item": item, "inventory": inventory_level.labels(item=item)._value.get()})


@app.route("/simulate")
def simulate():
    delay = float(request.args.get("delay", random.uniform(0.01, 0.5)))
    time.sleep(delay)
    return jsonify({"simulated_delay_seconds": delay})


@app.route("/metrics")
def metrics():
    return generate_latest(registry), 200, {"Content-Type": CONTENT_TYPE_LATEST}


def background_metrics_updater():
    while True:
        active_users.set(random.randint(10, 200))
        inventory_level.labels(item="widget").set(random.randint(50, 150))
        inventory_level.labels(item="gadget").set(random.randint(20, 100))
        queue_depth.labels(queue="default").set(random.randint(0, 20))
        queue_depth.labels(queue="priority").set(random.randint(0, 10))
        time.sleep(10)


if __name__ == "__main__":
    t = threading.Thread(target=background_metrics_updater, daemon=True)
    t.start()
    app.run(host="0.0.0.0", port=5000)